function length_of_lis(nums) {
    if (nums.length === 0) return 0;

    // tails[i] stores the smallest tail element for an increasing subsequence of length i+1
    const tails = [];

    for (const num of nums) {
        // Binary search for the position where num should be placed
        let left = 0;
        let right = tails.length;

        while (left < right) {
            const mid = Math.floor((left + right) / 2);
            if (tails[mid] < num) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }

        // If left == tails.length, num extends the longest subsequence
        if (left === tails.length) {
            tails.push(num);
        } else {
            // Otherwise, replace the existing element to maintain smallest tail
            tails[left] = num;
        }
    }

    return tails.length;
}
