function coin_change(coins, amount) {
    // Initialize dp array where dp[i] represents the minimum coins needed for amount i
    // Use a large number to represent infinity (unreachable)
    const INF = amount + 1;
    const dp = new Array(amount + 1).fill(INF);

    // Base case: 0 coins needed to make amount 0
    dp[0] = 0;

    // Fill dp table
    for (let i = 1; i <= amount; i++) {
        for (const coin of coins) {
            if (coin <= i) {
                dp[i] = Math.min(dp[i], dp[i - coin] + 1);
            }
        }
    }

    // If dp[amount] is still INF, it means the amount cannot be made
    return dp[amount] > amount ? -1 : dp[amount];
}
