function next_permutation(nums) {
    if (!nums || nums.length <= 1) return nums;

    const n = nums.length;

    // Step 1: Find the first decreasing element from the end
    let i = n - 2;
    while (i >= 0 && nums[i] >= nums[i + 1]) {
        i--;
    }

    // If no such element is found, the array is in descending order.
    // Reverse the entire array to get the smallest permutation.
    if (i === -1) {
        reverse(nums, 0, n - 1);
        return nums;
    }

    // Step 2: Find the smallest element to the right of i that is greater than nums[i]
    let j = n - 1;
    while (j >= 0 && nums[j] <= nums[i]) {
        j--;
    }

    // Step 3: Swap nums[i] and nums[j]
    swap(nums, i, j);

    // Step 4: Reverse the suffix starting at i + 1
    reverse(nums, i + 1, n - 1);

    return nums;
}

function swap(arr, i, j) {
    const temp = arr[i];
    arr[i] = arr[j];
    arr[j] = temp;
}

function reverse(arr, start, end) {
