function parse_csv_row(line) {
    const fields = [];
    let i = 0;
    const len = line.length;

    while (i <= len) {
        if (i === len) {
            // End of string, push empty field if we were in the middle or just starting
            if (fields.length > 0 || line === '') {
                fields.push('');
            }
            break;
        }

        let field = '';

        if (line[i] === '"') {
            // Quoted field
            i++; // skip opening quote
            while (i < len) {
                if (line[i] === '"') {
                    if (i + 1 < len && line[i + 1] === '"') {
                        // Escaped double quote
                        field += '"';
                        i += 2;
                    } else {
                        // End of quoted field
                        i++; // skip closing quote
                        break;
                    }
                } else {
                    field += line[i];
                    i++;
                }
            }

            // After closing quote, expect comma or end of string
            if (i < len && line[i] === ',') {
                i++; // skip comma
            }
        } else {
            // Unquoted field
            while (i < len && line[i] !== ',') {
                field += line[i];
                i++;
            }
            if (i < len && line[i] === ',') {
                i++; // skip comma
            }
        }

        fields.push(field);
    }

    return fields;
}
