function num_decodings(s) {
    if (!s || s.length === 0) return 0;

    const n = s.length;
    const dp = new Array(n + 1).fill(0);
    dp[0] = 1;
    dp[1] = (s[0] !== '0') ? 1 : 0;

    for (let i = 2; i <= n; i++) {
        if (s[i-1] !== '0') {
            dp[i] += dp[i-1];
        }
        const twoDigit = parseInt(s.substring(i-2, i));
        if (twoDigit >= 10 && twoDigit <= 26) {
            dp[i] += dp[i-2];
