function deep_merge(target, source) {
  const isPlainObject = (val) => 
    val !== null && 
    typeof val === 'object' && 
    Object.prototype.toString.call(val) === '[object Object]';

  const result = {};
  const keys = new Set([...Object.keys(target), ...Object.keys(source)]);

