function text_wrap(text, width) {
    const words = text.trim().split(/\s+/);
    const lines = [];

    if (words.length === 0) return lines;

    let currentLine = words[0];

    for (let i = 1; i < words.length; i++) {
        const nextWord = words[i];

        // If the word itself is longer than width, it goes on its own line
        if (nextWord.length > width) {
            lines.push(currentLine);
            currentLine = nextWord;
        } else if (currentLine.length + 1 + nextWord.length <= width) {
            // Fits on the current line
            currentLine += ' ' + nextWord;
        } else {
            // Doesn't fit, push current line and start new one
            lines.push(currentLine);
            currentLine = nextWord;
        }
    }

    // Push the last line
    if (currentLine.length > 0) {
        lines.push(currentLine);
    }

    return lines;
}
