function tokenize(expr) {
  const tokens = [];
  let i = 0;
  while (i < expr.length) {
    const char = expr[i];

    // Skip whitespace
    if (char === ' ' || char === '\t' || char === '\n' || char === '\r') {
      i++;
      continue;
    }

    // Check for negative number: '-' followed by a digit, and it's either at the start or after an operator/open-paren
    if (char === '-' && (i === 0 || ['+', '-', '*', '/', '^', '('].includes(expr[i - 1]))) {
      let numStr = '-';
      i++;
      while (i < expr.length && (expr[i] >= '0' && expr[i] <= '9')) {
        numStr += expr[i];
        i++;
      }
      // Check for decimal part
      if (i < expr.length && expr[i] === '.') {
        numStr += '.';
        i++;
        while (i < expr.length && (expr[i] >= '0' && expr[i] <= '9')) {
          numStr += expr[i];
          i++;
        }
      }
      tokens.push(numStr);
      continue;
    }

    // Check for positive number (integer or decimal)
    if ((char >= '0' && char <= '9') || (char === '.' && i + 1 < expr.length && expr[i + 1] >= '0' && expr[i + 1] <= '9')) {
      let numStr = '';
      while (i < expr.length && ((expr[i] >= '0' && expr[i] <= '9') || expr[i] === '.')) {
        numStr += expr[i];
        i++;
      }
      tokens.push(numStr);
      continue;
    }

    // Operators and parentheses
    if (['+', '-', '*', '/', '^', '(', ')'].includes(char)) {
      tokens.push(char);
      i++;
      continue;
    }

    // Skip any other characters (or throw error, but spec doesn't mention them)
    i++;
  }

