function tokenize(expr) {
  const tokens = [];
  let i = 0;

  while (i < expr.length) {
    const char = expr[i];

    if (/\s/.test(char)) {
      i++;
      continue;
    }

    // Check for negative numbers: 
    // '-' is part of a number if it's at the start or follows '(' or an operator
    if (char === '-') {
      const prevChar = tokens.length > 0 ? tokens[tokens.length - 1] : null;
      const isStart = tokens.length === 0;
      const isAfterOpening = isStart || prevChar === '(';
      const isAfterOperator = !isStart && ['+', '-', '*', '/', '^'].includes(prevChar);

      if (isStart || isAfterOpening || isAfterOperator) {
        // Check if next char is a digit (to avoid treating '-' as a number if followed by '(' or space)
        let nextIdx = i + 1;
        while (nextIdx < expr.length && /\s/.test(expr[nextIdx])) nextIdx++;

        if (nextIdx < expr.length && /[0-9]/.test(expr[nextIdx])) {
          let numStr = '-';
          i++;
          while (i < expr.length && /[0-9.]/.test(expr[i])) {
            numStr += expr[i];
            i++;
          }
          tokens.push(numStr);
          continue;
        }
      }
    }

    // Numbers (positive/decimal)
    if (/[0-9]/.test(char)) {
      let numStr = '';
      while (i < expr.length && /[0-9.]/.test(expr[i])) {
        numStr += expr[i];
        i++;
      }
      tokens.push(numStr);
      continue;
    }

    // Operators and Parentheses
    if ('+-*/^()'.includes(char)) {
      tokens.push(char);
      i++;
      continue;
    }

    i++; // Skip unknown characters
  }

  return tokens;
}
