function count_inversions(arr) {
  const n = arr.length;
  if (n < 2) return 0;

  const temp = new Array(n);
  const copy = [...arr];

  function mergeAndCount(left, mid, right) {
    let i = left;
    let j = mid + 1;
    let k = left;
    let invCount = 0;

    while (i <= mid && j <= right) {
      if (copy[i] <= copy[j]) {
        temp[k++] = copy[i++];
      } else {
        temp[k++] = copy[j++];
        invCount += (mid - i + 1);
      }
    }

    while (i <= mid) {
      temp[k++] = copy[i++];
    }
    while (j <= right) {
      temp[k++] = copy[j++];
    }

    for (let idx = left; idx <= right; idx++) {
      copy[idx] = temp[idx];
    }

    return invCount;
  }

  function sortAndCount(left, right) {
    let invCount = 0;
    if (left < right) {
      const mid = Math.floor((left + right) / 2);
      invCount += sortAndCount(left, mid);
      invCount += sortAndCount(mid + 1, right);
      invCount += mergeAndCount(left, mid, right);
