function num_decodings(s) {
  if (!s || s.length === 0) return 0;

  const n = s.length;
  const dp = new Array(n + 1).fill(0);

  // Base case: An empty string (prefix) has one way to be decoded.
  dp[0] = 1;

  // Base case: For the first character, if it's not '0', there's one way.
  dp[1] = s[0] === '0' ? 0 : 1;

  for (let i = 2; i <= n; i++) {
    // Check single digit: s[i-1]
    const singleDigit = parseInt(s.substring(i - 1, i));
    if (singleDigit >= 1 && singleDigit <= 9) {
      dp[i] += dp[i - 1];
