function largest_rectangle_area(heights) {
  let maxArea = 0;
  const stack = [];
  // We add a 0 at the end to ensure all remaining elements are popped from the stack
  const h = [...heights, 0];

  for (let i = 0; i < h.length; i++) {
    // While the current height is smaller than the height at the index on the stack top,
    // we found the right boundary for the bar at stack.top().
    while (stack.length > 0 && h[stack[stack.length - 1]] > h[i]) {
      const height = h[stack.pop()];
      // The width is determined by the current index and the new top of the stack
      const width = stack.length === 0 ? i : i - stack[stack.length - 1] - 1;
      maxArea = Math.max(maxArea, height * width);
