class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.map = new Map();
    // Dummy nodes to simplify edge cases in doubly linked list
    this.head = { key: null, value: null, prev: null, next: null };
    this.tail = { key: null, value: null, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * @param {number} key
   * @return {number}
   */
  get(key) {
    if (!this.map.has(key)) {
      return -1;
    }
    const node = this.map.get(key);
    this._remove(node);
    this._add(node);
    return node.value;
  }

  /**
   * @param {number} key
   * @param {number} value
   * @return {void}
   */
  put(key, value) {
    if (this.map.has(key)) {
      const node = this.map.get(key);
      node.value = value;
      this._remove(node);
      this._add(node);
    } else {
      const newNode = {
        key: key,
        value: value,
        prev: null,
        next: null
      };

      if (this.map.size >= this.capacity) {
        const lruNode = this.tail.prev;
        this._remove(lruNode);
        this.map.delete(lruNode.key);
      }

      this._add(newNode);
      this.map.set(key, newNode);
    }
  }

  /**
   * Removes a node from the doubly linked list.
   * @param {Object} node
   * @private
   */
  _remove(node) {
    const prev = node.prev;
    const next = node.next;
    prev.next = next;
    next.prev = prev;
  }

  /**
   * Adds a node to the front of the list (immediately after head).
   * @param {Object} node
   * @private
   */
  _add(node) {
    const next = this.head.next;
    this.head.next = node;
    node.prev = this.head;
    node.next = next;
    next.prev = node;
  }
}
