```javascript
function tokenize(expr) {
  const tokens = [];
  let i = 0;
  while (i < expr.length) {
    const char = expr[i];

    // Skip whitespace
    if (/\s/.test(char)) {
      i++;
      continue;
    }

    if (char === '-') {
      // A '-' is a negative sign if it's the first token or follows an operator/opening parenthesis.
      // This matches the behavior of the example '(1+2)*-3' -> '-3'.
      const lastToken = tokens.length > 0 ? tokens[tokens.length - 1] : null;
      const isNegativeSign = lastToken === null || ['+', '-', '*', '/', '^', '('].includes(lastToken);

      if (isNegativeSign) {
        let j = i + 1;
        // Skip whitespace between '-' and the number
        while (j < expr.length && /\s/.test(expr[j])) {
          j++;
        }
        let start = j;
        // Collect the numeric part (digits or decimal point)
        while (j < expr.length && /[0-9.]/.test(expr[j])) {
          j++;
        }

        if (j > start) {
          // We found a number following the '-'
          tokens.push("-" + expr.substring(start, j));
          i = j;
        } else {
          // It's just a subtraction/unary minus operator without an immediate number
          tokens.push("-");
          i++;
        }
      } else {
        // It's a standard subtraction operator
        tokens.push("-");
        i++;
      }
    } else if (/[0-9.]/.test(char)) {
      // Collect integer or decimal numbers
      let start = i;
      while (i < expr.length && /[0-9.]/.test(expr[i])) {
        i++;
      }
      tokens.push(expr.substring(start, i));
    } else {
      // Other operators and parentheses
      tokens.push(char);
      i++;
    }
  }
  return tokens;
}
