    // A '-' is part of a number if it is at the start or follows '(' or an operator
    const isUnaryMinus = (char === '-') && (i === 0 || expr[i - 1].match(/[+\-*/^(]/) || /\s/.test(expr[i - 1]));

    // If it's a digit or a decimal point (not part of a standalone dot), or a valid unary minus
    if (/[0-9.]/.test(char) || (char === '-' && isUnaryMinus)) {
      let numStr = '';

      // Handle the negative sign if it's part of the number
      if (char === '-') {
        numStr += char;
        i++;
      }

      // Collect digits and decimal point
      while (i < expr.length && /[0-9.]/.test(expr[i])) {
        numStr += expr[i];
        i++;
      }

      // If we consumed just a '-' without digits, it's an operator, not a number
      if (numStr === '-') {
        tokens.push('-');
      } else {
        tokens.push(numStr);
        continue; // i is already incremented
      }
    } else {
