  let res = nums[0];
  let curMax = nums[0];
  let curMin = nums[0];

  for (let i = 1; i < nums.length; i++) {
    const n = nums[i];

    if (n < 0) {
      // When multiplying by a negative number, the max becomes the min and vice versa
      let temp = curMax;
      curMax = curMin;
      curMin = temp;
    }

    curMax = Math.max(n, curMax * n);
