function num_decodings(s) {
  if (!s || s.length === 0 || s[0] === '0') {
    return 0;
  }

  const n = s.length;
  const dp = new Array(n + 1).fill(0);

  // Base cases
  // dp[i] represents the number of ways to decode s.substring(0, i)
  dp[0] = 1;
  dp[1] = 1;

  for (let i = 2; i <= n; i++) {
    const oneDigit = parseInt(s[i - 1], 10);
    const twoDigits = parseInt(s.substring(i - 2, i), 10);

    // If the single digit is not zero, it's a valid character (A-I)
    if (oneDigit >= 1 && oneDigit <= 9) {
      dp[i] += dp[i - 1];
    }

    // If the two digits form a number between 10 and 26, it's a valid character (J-Z)
    if (twoDigits >= 10 && twoDigits <= 26) {
      dp[i] += dp[i - 2];
    }
  }

  return dp[n];
}
