class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key) {
    if (!this.map.has(key)) {
      return -1;
    }
    // Refresh key by deleting and re-inserting so it moves to the end (most recent)
    const value = this.map.get(key);
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  put(key, value) {
    if (this.map.has(key)) {
      // If key exists, delete it first to refresh its position
      this.map.delete(key);
    } else if (this.map.size === this.capacity) {
      // If at capacity, evict the least recently used (the first key in insertion order)
      const oldestKey = this.map.keys().next().value;
      this.map.delete(oldestKey);
    }
    this.map.set(key, value);
  }
}
