>>> flatten_object({a: {b: 1, c: {d: 2}}, e: 3})
{"a.b": 1, "a.c.d": 2, "e": 3}

response.output:
```javascript
function flatten_object(obj) {
  const result = {};

  function recurse(current, path) {
    // Check if current is a plain object (not null, not array, not Date, etc.)
    const isPlainObject = current !== null && 
                          typeof current === 'object' && 
                          current.constructor === Object;

    if (isPlainObject) {
      for (const key in current) {
        if (Object.prototype.hasOwnProperty.call(current, key)) {
          const newPath = path ? `${path}.${key}` : key;
          recurse(current[key], newPath);
        }
      }
    } else {
      result[path] = current;
    }
  }

  recurse(obj, "");
  return result;
}
```

```javascript
function text_wrap(text, width) {
  const words = text.trim().split(/\s+/);
  const lines = [];
  let currentLine = [];
  let currentLength = 0;

  for (let i = 0; i < words.length; i++) {
    const word = words[i];
    const wordLen = word.length;

    if (currentLine.length === 0) {
      currentLine.push(word);
      currentLength = wordLen;
    } else if (currentLength + 1 + wordLen <= width) {
      currentLine.push(word);
      currentLength += 1 + wordLen;
    } else {
      lines.push(currentLine.join(' '));
      currentLine = [word];
      currentLength = wordLen;
    }
  }

  if (currentLine.length > 0) {
    lines.push(currentLine.join(' '));
  }

  return lines;
}
```

