function rle_encode(s) {
  if (!s) return '';
  let result = '';
  let i = 0;

  while (i < s.length) {
    let char = s[i];
    let count = 0;

    while (i < s.length && s[i] === char) {
      count++;
      i++;
    }

    result += char + (count > 1 ? count : '');
