```javascript
function tokenize(expr) {
  const tokens = [];
  let i = 0;

  while (i < expr.length) {
    const char = expr[i];

    if (/\s/.test(char)) {
      i++;
      continue;
    }

    if (/[+\-*/^()]/.test(char)) {
      // Handle negative numbers: '-' is a part of the number if it is at the 
      // start of the string or immediately follows an opening parenthesis.
      if (char === '-') {
        const prevChar = i > 0 ? tokens[tokens.length - 1] : null;
        const isStartOfNumber = i === 0 || prevChar === '(';

        // Check if it's a unary minus followed by a digit
        const nextCharIdx = i + 1;
        if (isStartOfNumber && nextCharIdx < expr.length && /[0-9]/.test(expr[nextCharIdx])) {
          let numStr = '-';
          i++;
          while (i < expr.length && /[0-9.]/.test(expr[i])) {
            numStr += expr[i];
            i++;
          }
          tokens.push(numStr);
          continue;
        }
      }

      tokens.push(char);
      i++;
    } else if (/[0-9.]/.test(char)) {
      let numStr = '';
      while (i < expr.length && /[0-9.]/.test(expr[i])) {
        numStr += expr[i];
        i++;
      }
      tokens.push(numStr);
    } else {
      i++;
    }
  }

  return tokens;
}
```

