function count_inversions(arr) {
  function mergeAndCount(left, right) {
    const result = [];
    let count = 0;
    let i = 0;
    let j = 0;

    while (i < left.length && j < right.length) {
      if (left[i] <= right[j]) {
        result.push(left[i]);
        i++;
      } else {
        result.push(right[j]);
        count += left.length - i;
        j++;
      }
    }

    while (i < left.length) {
      result.push(left[i]);
      i++;
    }
    while (j < right.length) {
      result.push(right[j]);
      j++;
    }

    return { result, count };
  }

  function sortAndCount(tempArr) {
    if (tempArr.length <= 1) {
      return { result: tempArr, count: 0 };
    }

    const mid = Math.floor(tempArr.length / 2);
    const leftResult = sortAndCount(tempArr.slice(0, mid));
    const rightResult = sortAndCount(tempArr.slice(mid));
    const mergedResult = mergeAndCount(leftResult.result, rightResult.result);

    return {
      result: mergedResult.result,
      count: leftResult.count + rightResult.count + mergedResult.count,
    };
  }

  return sortAndCount(arr).count;
}
