function max_product(nums) {
  if (nums.length === 0) return 0;

  let max_prod = nums[0];
  let current_max = nums[0];
  let current_min = nums[0];

  for (let i = 1; i < nums.length; i++) {
    const val = nums[i];

    if (val < 0) {
      let temp = current_max;
      current_max = current_min;
      current_min = temp;
    }

    current_max = Math.max(val, current_max * val);
    current_min = Math.min(val, current_min * val);

    max_prod = Math.max(max_prod, current_max);
  }

  return max_prod;
}
