```javascript
function num_decodings(s) {
  if (!s || s[0] === '0') {
    return 0;
  }

  const n = s.length;
  const dp = new Array(n + 1).fill(0);

  // Base cases
  // dp[0] represents an empty string, which has 1 way to be decoded (by doing nothing).
  // dp[1] represents a string of length 1. Since we already checked s[0] !== '0', dp[1] is 1.
  dp[0] = 1;
  dp[1] = 1;

  for (let i = 2; i <= n; i++) {
    // Check single-digit decoding (s[i-1])
    const singleDigit = parseInt(s.substring(i - 1, i));
    if (singleDigit >= 1 && singleDigit <= 9) {
      dp[i] += dp[i - 1];
    }

    // Check two-digit decoding (s[i-2] and s[i-1])
    const doubleDigit = parseInt(s.substring(i - 2, i));
    if (doubleDigit >= 10 && doubleDigit <= 26) {
      dp[i] += dp[i - 2];
    }
  }

  return dp[n];
}
```

```javascript
function spiral_order(matrix) {
  if (matrix.length === 0) return [];

  const result = [];
  let top = 0;
  let bottom = matrix.length - 1;
  let left = 0;
  let right = matrix[0].length - 1;

  while (top <= bottom && left <= right) {
    // Move right
    for (let j = left; j <= right; j++) {
      result.push(matrix[top][j]);
    }
    top++;

    // Move down
    for (let i = top; i <= bottom; i++) {
      result.push(matrix[i][right]);
    }
    right--;

    // Move left
    if (top <= bottom) {
      for (let j = right; j >= left; j--) {
        result.push(matrix[bottom][j]);
      }
      bottom--;
    }

    // Move up
    if (left <= right) {
      for (let i = bottom; i >= top; i--) {
        result.push(matrix[i][left]);
      }
      left++;
    }
  }

  return result;
}
```

