function tokenize(expr) {
  const tokens = [];
  let i = 0;

  while (i < expr.length) {
    const char = expr[i];

    if (/\s/.test(char)) {
      i++;
      continue;
    }

    if (['+', '-', '*', '/', '^', '(', ')'].includes(char)) {
      if (char === '-') {
        let isUnary = false;
        if (i === 0) {
          isUnary = true;
        } else {
          let prevIdx = i - 1;
          while (prevIdx >= 0 && /\s/.test(expr[prevIdx])) {
            prevIdx--;
          }
          if (prevIdx >= 0) {
            const prevChar = expr[prevIdx];
            if (['(', '+', '-', '*', '/', '^'].includes(prevChar)) {
              isUnary = true;
            }
          }
        }

        if (isUnary) {
          let j = i + 1;
          while (j < expr.length && /\s/.test(expr[j])) {
            j++;
          }
          if (j < expr.length && /[\d.]/.test(expr[j])) {
            let numStr = '-';
            i = j;
            while (i < expr.length && /[\d.]/.test(expr[i])) {
              numStr += expr[i];
              i++;
            }
            tokens.push(numStr);
            continue;
          }
        }
      }
      tokens.push(char);
      i++;
    } else if (/[\d.]/.test(char)) {
      let numStr = '';
      while (i < expr.length && /[\d.]/.test(expr[i])) {
        numStr += expr[i];
        i++;
      }
      tokens.push(numStr);
    } else {
      i++;
    }
  }

  return tokens;
}
